{
  "analysis": {
    "summary": "Handles new user onboarding with email verification.",
    "scope": "Generate detail design for registration and activation workflow.",
    "entities": ["User", "VerificationToken", "Profile"],
    "businessFlows": [
      "Submit registration",
      "Validate unique email",
      "Create inactive user",
      "Issue verification token",
      "Send verification email",
      "Confirm activation"
    ],
    "apiCandidates": ["POST /api/register", "POST /api/register/verify"],
    "uiSignals": ["Registration form", "Profile summary panel"],
    "risks": ["Duplicate account creation", "Expired verification tokens"],
    "assumptions": ["Email delivery is asynchronous", "Account stays inactive until verification completes"]
  },
  "detailDesign": {
    "screen": {
      "01_UI_Design": "Registration screen with email, password, confirm password, and profile summary states.",
      "02_Components": "RegistrationForm, PasswordPolicyHint, ProfileSummaryPanel, VerificationNotice.",
      "03_Data_Models": "User, VerificationToken, Profile.",
      "04_API_Integration": "POST /api/register, POST /api/register/verify.",
      "05_Business_Logic": "Validate password policy, enforce unique email, create inactive account, send verification link, activate account after token validation.",
      "06_State_Management": "Track form input, submission state, verification pending state, and activation success state."
    },
    "api": {
      "01_Contract": "Expose registration and verification endpoints with validation errors and activation result.",
      "02_Business_Logic": "Hash password before persistence, generate one-time token, verify token expiry, activate account atomically.",
      "03_Data_Access": "Use users, verification_tokens, and audit_log tables with indexed email lookup."
    },
    "batch": {
      "01_Job_Definition": "Async notification job for verification email delivery.",
      "02_Processing_Logic": "Queue verification email after registration and retry transient mail provider failures.",
      "03_Data_Access": "Read pending email payload and persist delivery attempts in audit_log."
    }
  },
  "review": {
    "status": "PASS",
    "findings": [],
    "strengths": ["Covers screen, API, and async notification concerns for onboarding."],
    "nextActions": ["Approved sample for account onboarding modules."]
  }
}

