  "analysis": {
    "summary": "Manages create, update, publish, archive, and listing for catalog products.",
    "scope": "Generate detail design for CRUD-heavy product management API and admin UI.",
    "entities": ["Product", "ProductCategory", "ProductImage"],
    "businessFlows": [
      "Create product draft",
      "Validate SKU uniqueness",
      "Update pricing",
      "Publish product",
      "Archive obsolete product"
    ],
    "apiCandidates": [
      "GET /api/products",
      "POST /api/products",
      "PUT /api/products/{id}",
      "POST /api/products/{id}/publish"
    ],
    "uiSignals": ["Product list", "Product detail form", "Archive confirmation dialog"],
    "risks": ["Invalid state transitions", "Duplicate SKU conflicts"],
    "assumptions": ["Product editing is done by authenticated admin users", "Published products require audit events"]
  },
  "detailDesign": {
    "screen": {
      "01_UI_Design": "Admin product list with filters, editable detail form, and archive confirmation dialog.",
      "02_Components": "ProductTable, ProductForm, CategorySelector, PublishActionBar, ArchiveDialog.",
      "03_Data_Models": "Product, ProductCategory, ProductImage.",
      "04_API_Integration": "GET /api/products, POST /api/products, PUT /api/products/{id}, POST /api/products/{id}/publish.",
      "05_Business_Logic": "Allow draft edits, prevent duplicate SKU, validate pricing rules, and separate publish from save draft.",
      "06_State_Management": "Track list filters, selected product, draft form changes, publish action status, and archive confirmation state."
    },
    "api": {
      "01_Contract": "Expose product list, create, update, publish, and archive operations with explicit validation responses.",
      "02_Business_Logic": "Keep draft and published states explicit, recalculate derived pricing, emit audit events on publish, and reject duplicate SKU updates.",
      "03_Data_Access": "Persist products, categories, and images in dedicated tables with SKU uniqueness constraints and publish audit history."
    },
    "batch": {
      "01_Job_Definition": "Catalog re-index job after publish or archive.",
      "02_Processing_Logic": "Trigger downstream search/index refresh when product visibility changes.",
      "03_Data_Access": "Read changed product IDs and persist re-index execution logs."
    }
  },
  "review": {
    "status": "PASS",
    "findings": [],
    "strengths": ["Strong sample for CRUD-heavy management modules with explicit lifecycle states."],
    "nextActions": ["Approved sample for catalog and admin maintenance modules."]
  }
}

{
  "analysis": {
    "summary": "Scheduled synchronization of order statuses from external partner system.",
    "scope": "Generate detail design for async integration and operational sync monitoring.",
    "entities": ["Order", "OrderSyncJob", "PartnerOrderStatus"],
    "businessFlows": [
      "Start sync job",
      "Fetch changed partner orders",
      "Map external statuses",
      "Update internal order state",
      "Persist sync report"
    ],
    "apiCandidates": ["GET partner/orders/changes", "POST /api/order-sync-jobs"],
    "uiSignals": ["Sync job monitoring screen", "Failure detail view"],
    "risks": ["Partner API timeout", "Duplicate updates across retries"],
    "assumptions": ["Sync runs every 15 minutes", "Order status updates must be idempotent"]
  },
  "detailDesign": {
    "screen": {
      "01_UI_Design": "Operations screen showing sync history, current job state, and failed order detail view.",
      "02_Components": "SyncJobTable, FailureSummaryCard, JobDetailDrawer, RetryActionButton.",
      "03_Data_Models": "Order, OrderSyncJob, PartnerOrderStatus.",
      "04_API_Integration": "GET partner/orders/changes, POST /api/order-sync-jobs.",
      "05_Business_Logic": "Display job progress, surface partial failures, and allow targeted investigation of failed order mappings.",
      "06_State_Management": "Track polling state for current job, selected failure record, and retry action state."
    },
    "api": {
      "01_Contract": "Expose internal sync job creation, status retrieval, failure summary, and order-level diagnostics.",
      "02_Business_Logic": "Retry transient partner failures, map partner statuses to internal states, ensure idempotent writes, and mark partial completion when needed.",
      "03_Data_Access": "Persist sync job summary, updated orders, and failed records in order_sync_jobs and order_sync_failures tables."
    },
    "batch": {
      "01_Job_Definition": "Cron-triggered order sync job running every 15 minutes.",
      "02_Processing_Logic": "Fetch partner deltas, transform statuses, update orders, collect failures, and persist run summary.",
      "03_Data_Access": "Read partner delta cursor, update orders table, and write execution/failure records for diagnostics."
    }
  },
  "review": {
    "status": "PASS",
    "findings": [],
    "strengths": ["Good sample for async integration, retries, and partial-failure batch handling."],
    "nextActions": ["Approved sample for operational batch and partner sync modules."]
  }
}
